import React, { FC } from 'react';
import './CardTemplate.scss';
import { Button } from ':components/Button';
import { Icon } from ':components/Icon';
import { Label } from ':components/Label';
import { Typography } from ':components/Typography';
import { classNames } from ':helpers/classnames';
import { CardTemplateAction, CardTemplateProps } from './CardTemplate.types';

export const CardTemplate: FC<CardTemplateProps> = ({
	icon,
	image,
	imagePosition = 'left',
	imageAlt,
	header,
	headline,
	labels,
	actions,
	href,
	disabled = false,
	onAction,
	dataTestId = 'CardTemplate',
	className,
	children,
	...rest
}) => {
	const base = 'dsb_cardtemplate';

	const handleAction = (action: CardTemplateAction) => (e?: React.MouseEvent) => {
		onAction?.(action, e);
	};

	const renderImg = () => {
		if (!image) return null;
		return (
			<div className={`${base}__image`}>{typeof image === 'string' ? <img src={image} alt={imageAlt} /> : image}</div>
		);
	};

	const renderHeader = () => {
		return (
			<Typography inactive={disabled} className={`${base}__header `} variant="h4">
				{header}
			</Typography>
		);
	};

	const renderTopMeta = () => {
		if (!icon) return null;
		return (
			<div className={`${base}__meta`}>{icon && <Icon className={`${base}__icon`} contained iconName={icon} />}</div>
		);
	};

	const renderLabels = () => {
		if (!labels?.length) return null;

		return (
			<div className={`${base}__labels`}>
				{labels.map((l, i) => (
					<Label className={`${base}__label`} title={l.title} />
				))}
			</div>
		);
	};

	const renderActions = () => {
		if (!actions?.length) return null;
		return (
			<div className={`${base}__actions`}>
				{actions.map((action, index) => (
					<Button
						key={`card-action-${index}`}
						type="button"
						size={'medium'}
						onClick={handleAction(action)}
						disabled={action.disabled || disabled}
						className={action.hidden && `${base}__actions-hidden`}
						aria-label={action['aria-label']}
						{...action}
					>
						{action.label}
					</Button>
				))}
			</div>
		);
	};

	return React.cloneElement<any>(href ? <a /> : <React.Fragment />, {
		children: (
			<div
				className={classNames(
					base,
					`${base}_pos-${image ? imagePosition : 'none'}`,
					href && `${base}-link`,
					disabled ? `${base}_disabled` : '',
					className,
				)}
				data-testId={dataTestId}
				{...rest}
			>
				{renderImg()}
				<div className={`${base}__content`}>
					{renderTopMeta()}
					<div className={`${base}__head`}>
						{renderHeader()}

						<Typography inactive variant="body3" className={`${base}__headline`}>
							{headline}
						</Typography>
					</div>

					{renderLabels()}

					{children}

					{renderActions()}
				</div>
			</div>
		),
	});
};

export default CardTemplate;
